import axios from 'axios';

const api = {
  fetchCategories: () => axios.get('/data/category.json'),
  addCategory: (data) => axios.post('/api/categories', data),
  fetchGoods: () => axios.get('/data/goods.json'),
  registerGoods: (data) => axios.post('/api/goods', data),
  searchGoods: (kw) => axios.get(`/api/goods/search?kw=${kw}`),
  getGoodsDetail: (id) => axios.get(`/api/goods/${id}`),
  addReview: (data) => axios.post('/api/reviews', data),
  getReviews: (goodsId) => axios.get(`/api/reviews?goodsId=${goodsId}`)
};

export default api;
